+            ("test", "pty_vfx_harness_deterministic_hashes".to_string()),
+            ("bin", demo_bin.clone()),
+        ],
+    );
+
+    let hashes_a = run_vfx_harness(&demo_bin, "vfx_harness_run_a")?;
+    let hashes_b = run_vfx_harness(&demo_bin, "vfx_harness_run_b")?;
+
+    if hashes_a.is_empty() {
